nta.declaration:
/** Every production unit has two outputs which feed into other production units or to outlets. If a production unit doesn't receive output from another unit, it receives it from an intake that delivers material according to a cyclic pattern. */ clock time; // Used as exit condition for the strategy queries const int N = 4; // Number of rows of units const int M = 3; // Production units per row const int LEFT = 0; // Constant to add if this is a left output const int RIGHT = N*M; // Constant to add if this is a right output typedef int[0, N*M - 1] UnitID; typedef int[0, N*M*2 - 1] OutputID;
const double MIN_STORED = 1; // Unit: L const double MAX_STORED = 11; // Unit: L const double PRODUCTION_RATE = 1; // Unit: L/h
clock stored[N*M]; // Material stored in each tank. Unit: L double output[N*M*2]; // Outputs of production unit. Left outputs are indexed by unit_id+LEFT = unit_id, right outputs by unit_id+RIGHT. Unit: L/h

nta.system:
// Row 0 - Intakes
I00 = Intake(0*M+0, 0.0, 2.0, 2.0, 1.0, 0.0);
I01 = Intake(0*M+1, 1.0, 1.0, 0.0, 2.0, 1.0);
I02 = Intake(0*M+2, 1.0, 1.0, 1.0, 0.0, 1.0);

// Row 1 - first row of production units
U10 = ProductionUnit(1*M+0, 0*M+0 + LEFT, 0*M+0 + RIGHT);
U11 = ProductionUnit(1*M+1, 0*M+1 + LEFT, 0*M+1 + RIGHT);
U12 = ProductionUnit(1*M+2, 0*M+2 + LEFT, 0*M+2 + RIGHT);

// Row 2
U20 = ProductionUnit(2*M+0, 1*M+0 + LEFT,  1*M+1 + LEFT);
U21 = ProductionUnit(2*M+1, 1*M+0 + RIGHT, 1*M+2 + LEFT);
U22 = ProductionUnit(2*M+2, 1*M+1 + RIGHT, 1*M+2 + RIGHT);

// Row 3
U30 = ProductionUnit(3*M+0, 2*M+0 + LEFT,  2*M+1 + LEFT);
U31 = ProductionUnit(3*M+1, 2*M+0 + RIGHT, 2*M+2 + LEFT);
U32 = ProductionUnit(3*M+2, 2*M+1 + RIGHT, 2*M+2 + RIGHT);

// Row N+1 - Outlets (Outlets don't have an ID)
O0 = Outlet( 1.0, 2*M+0 + LEFT,  2*M+1 + LEFT); 
O1 = Outlet( 0.5, 2*M+0 + RIGHT, 2*M+2 + LEFT);
O2 = Outlet(-1, 2*M+1 + RIGHT, 2*M+2 + RIGHT);
system I00, I01, I02, U10, U11, U12, U20, U21, U22, U30, U31, U32, O0, O1, O2;


/** Layout: Lines show pipes providing material to next layer

 [0, 0] [0, 1]  [0, 2] Intakes
  |   \ /     \ /   |
  |    x       x    |
  |   / \     / \   |
 [1, 0] [1, 1]  [1, 2] Row 1
  |   \ /     \ /   |
  |    x       x    |
  |   / \     / \   |
 [2, 0] [2, 1]  [2, 2] Row 2 
  |   \ /     \ /   |
  |    x       x    |
  |   / \     / \   |
 [3, 0] [3, 1]  [3, 2] Row 3
  |   \ /     \ /   |
  |    x       x    |
  |   / \     / \   |
 [ O0 ] [ O1 ] [ O2 ] Outlets

*/
